styles.css:
.has-drop-cap:not(:focus)::first-letter {
  font-size: 4em;
  font-weight: bold;
  float: left;
  line-height: 0.8;
  margin-right: 8px;
  color: #0E2F3B;
  font-family: serif;
}
//calendar

/* Wrapper */
.my-custom-styled-calendar {
    max-width: 380px;
    margin: 0 auto;
    padding: 20px;
    background: #f8f8f8;
    border-radius: 16px;
    box-shadow: 0 4px 14px rgba(0, 0, 0, 0.08);
    font-family: inherit;
}

/* Main calendar table */
.my-custom-styled-calendar #wp-calendar {
    width: 100%;
    border-collapse: separate;
    border-spacing: 8px;
    text-align: center;
    table-layout: fixed;
}

/* Caption = month/year */
.my-custom-styled-calendar #wp-calendar caption {
    caption-side: top;
    font-size: 28px;
    font-weight: 700;
    color: #1f2937;
    margin-bottom: 18px;
    text-align: center;
}

/* Header row: Sun Mon Tue... */
.my-custom-styled-calendar #wp-calendar thead th {
    font-size: 15px;
    font-weight: 600;
    color: #6b7280;
    padding: 10px 0;
    border: none;
}

/* All cells */
.my-custom-styled-calendar #wp-calendar tbody td,
.my-custom-styled-calendar #wp-calendar tfoot td {
    padding: 0;
    border: none;
    background: transparent;
}

/* Day links */
.my-custom-styled-calendar #wp-calendar tbody td a {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 38px;
    height: 38px;
    text-decoration: none;
    border-radius: 8px;
    font-weight: 600;
    color: #1f2937;
    background: #ffffff;
    transition: all 0.2s ease;
}

/* Normal day numbers without links */
.my-custom-styled-calendar #wp-calendar tbody td {
    width: 40px;
    height: 40px;
    vertical-align: middle;
    font-size: 16px;
    font-weight: 500;
    color: #374151;
}

/* Hover effect */
.my-custom-styled-calendar #wp-calendar tbody td a:hover {
    background: #facc15;
    color: #111827;
    transform: translateY(-1px);
}

/* Today's date */
.my-custom-styled-calendar #wp-calendar tbody td#today {
    background: #eab308;
    color: #111827;
    border-radius: 8px;
    font-weight: 700;
}

/* If today also contains a link */
.my-custom-styled-calendar #wp-calendar tbody td#today a {
    background: #eab308;
    color: #111827;
    width: 38px;
    height: 38px;
    border-radius: 8px;
    font-weight: 700;
}

/* Empty cells from previous/next month */
.my-custom-styled-calendar #wp-calendar tbody td.pad {
    color: #d1d5db;
    background: transparent;
}

/* Prev / Next row */
.my-custom-styled-calendar #wp-calendar tfoot {
    margin-top: 12px;
}

.my-custom-styled-calendar #wp-calendar tfoot td {
    padding-top: 14px;
    font-size: 14px;
    font-weight: 600;
}

/* Previous month link */
.my-custom-styled-calendar #wp-calendar tfoot #prev {
    text-align: left;
}

.my-custom-styled-calendar #wp-calendar tfoot #prev a {
    display: inline-block;
    padding: 8px 14px;
    background: #ffffff;
    border-radius: 10px;
    text-decoration: none;
    color: #1f2937;
    box-shadow: 0 2px 6px rgba(0,0,0,0.08);
}

/* Next month link */
.my-custom-styled-calendar #wp-calendar tfoot #next {
    text-align: right;
}

.my-custom-styled-calendar #wp-calendar tfoot #next a {
    display: inline-block;
    padding: 8px 14px;
    background: #ffffff;
    border-radius: 10px;
    text-decoration: none;
    color: #1f2937;
    box-shadow: 0 2px 6px rgba(0,0,0,0.08);
}

/* Hover for prev/next */
.my-custom-styled-calendar #wp-calendar tfoot a:hover {
    background: #facc15;
    color: #111827;
}

/* Optional: fallback message styling */
.my-custom-styled-calendar p {
    margin: 0;
    text-align: center;
    color: #6b7280;
    font-size: 16px;
}
